unitsize(0.15 cm);

pair F, P, Q;

real parab (real x) {
  return(-(x^2 - 6*x + 793)/56);
}

real upperparab(real x) {
  return(sqrt(3)*sqrt(2*x - 3) - 28);
}

real lowerparab(real x) {
  return(-sqrt(3)*sqrt(2*x - 3) - 28);
}

F = (3,-28);
P = (18.0385,-18.0385);
Q = (43.9615,-43.9615);

draw((-10,0)--(50,0));
draw((0,-50)--(0,10));
draw(graph(parab,-10,47),red);
draw(graph(upperparab,3/2,50),blue);
draw(graph(lowerparab,3/2,50),blue);
draw(F--P--(P.x,0));
draw(P--(0,P.y));
draw(F--Q--(Q.x,0));
draw(Q--(0,Q.y));
draw((-10,10)--(50,-50),dashed);

label("$F$", F, NW, UnFill);
label("$P$", P, NE, UnFill);
label("$Q$", Q, NE, UnFill);

dot(F);
[/asy]

